 1→import { getLogger } from "@logtape/logtape";
 2→import { ORPCError } from "@orpc/server";
 3→import { escapeString, queryClickhouse } from "./clickhouse.js";
 4→
 5→const logger = getLogger(["rudel", "api", "rate-limit"]);
 6→
 7→export interface RateLimitConfig {
 8→	maxRequests: number;
 9→	windowSeconds: number;
10→	countQuery: (userId: string, windowSeconds: number) => string;
11→}
12→
13→const ingestCountQuery = (userId: string, windowSeconds: number) =>
14→	`SELECT sum(c) AS count FROM (` +
15→	`SELECT count() AS c FROM rudel.claude_sessions WHERE user_id = '${userId}' AND ingested_at >= now64(3) - INTERVAL ${windowSeconds} SECOND ` +
16→	`UNION ALL ` +
17→	`SELECT count() AS c FROM rudel.codex_sessions WHERE user_id = '${userId}' AND ingested_at >= now64(3) - INTERVAL ${windowSeconds} SECOND` +
18→	`)`;
19→
20→export const INGEST_RATE_LIMIT: RateLimitConfig = {
21→	maxRequests: Number(process.env.RATE_LIMIT_INGEST_MAX ?? 120),
22→	windowSeconds: Number(process.env.RATE_LIMIT_INGEST_WINDOW ?? 3600),
23→	countQuery: ingestCountQuery,
24→};
25→
26→/**
27→ * Checks if a user has exceeded their rate limit.
